INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('e6568df367daec1f', 'NH', '["federal"]', 'candidate_eligibility', 'Is there a U.S. Senate race in New Hampshire for the 2026 cycle?', '["Who is running for Jeanne Shaheen''s Senate seat?","Is the New Hampshire US Senate seat an open race?","New Hampshire 2026 Senate election status"]', 'Yes. There is an open U.S. Senate race in New Hampshire in 2026. Incumbent Senator Jeanne Shaheen (D) announced on March 12, 2025, that she will not seek a fourth term. Senator Maggie Hassan is not on the ballot until 2028.', 'https://www.sos.nh.gov/elections/upcoming-elections', 'New Hampshire Secretary of State – Upcoming Elections', '2026-05-13', 'volatile', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('8986668234639b47', 'NH', '["state"]', 'candidate_eligibility', 'What is the term length for the Governor of New Hampshire?', '["How often does New Hampshire elect a Governor?","New Hampshire gubernatorial term duration","Is the NH Governor up for election every two years?"]', 'The Governor of New Hampshire serves a two-year term. New Hampshire is one of only two states (with Vermont) that holds gubernatorial elections in every even-numbered year under N.H. Const. Pt. 2, Art. 42.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 42', '2026-05-13', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('7e6ced06924e3a8a', 'NH', '["state"]', 'candidate_eligibility', 'Is Governor Kelly Ayotte running for re-election in 2026?', '["Is the New Hampshire Governor''s seat open in 2026?","Can Kelly Ayotte seek a second term?","NH Governor re-election status 2026"]', 'Yes. Governor Kelly Ayotte (R), who was elected to her first term in 2024, is eligible for re-election in 2026. New Hampshire has no term limits for the office of Governor.', 'https://www.sos.nh.gov/elections/candidates', 'New Hampshire Secretary of State – Candidates', '2026-05-13', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('03fb75f7c8042f17', 'NH', '["state"]', 'candidate_eligibility', 'What is the role of the New Hampshire Executive Council in approving appointments?', '["NH Executive Council veto power","What can the Executive Council approve?","Checking the power of the NH Governor"]', 'The Executive Council is a five-member elected body that checks the Governor''s power. Under N.H. Const. Pt. 2, Art. 47, the Governor and Council have a mutual ''negative'' on each other, meaning a 3-2 Council majority is required to approve contracts over $10,000, pardons, and gubernatorial appointments.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 47', '2026-05-13', 'static', 'statute_citation', 'Statewide candidates and Executive Council candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('89a9525024facdf2', 'NH', '["state"]', 'candidate_eligibility', 'Does New Hampshire have a Lieutenant Governor?', '["Who succeeds the NH Governor?","Is there a Lt. Governor on the NH ballot?","New Hampshire order of succession"]', 'No. New Hampshire does not have an office of Lieutenant Governor. Under N.H. Const. Pt. 2, Art. 49, the President of the Senate is the first in the line of succession to perform the duties of the Governor.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 49', '2026-05-13', 'static', 'statute_citation', 'Statewide officials and candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('6ef0ab76fe8acf46', 'NH', '["state"]', 'candidate_eligibility', 'How is the Attorney General selected in New Hampshire?', '["Is the NH Attorney General elected?","Appointment process for NH AG","Who picks the Attorney General in New Hampshire?"]', 'The Attorney General of New Hampshire is appointed by the Governor with the advice and consent of the Executive Council. The AG is not popularly elected by the voters and serves a four-year term per N.H. Const. Pt. 2, Art. 46 and RSA 7:1.', 'https://www.gencourt.state.nh.us/rsa/html/I/7/7-1.htm', 'RSA 7:1 and N.H. Const. Pt. 2, Art. 46', '2026-05-13', 'static', 'statute_citation', 'Statewide executive officials', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('09813ad181a6cfad', 'NH', '["state"]', 'candidate_eligibility', 'How is the New Hampshire Secretary of State chosen?', '["Is the NH Secretary of State an elected office?","Who chooses the Secretary of State in NH?","Joint ballot election for NH SoS"]', 'The Secretary of State is elected by a joint ballot of the New Hampshire House and Senate (the General Court) rather than by popular vote. This election occurs at the start of each new legislative session under N.H. Const. Pt. 2, Art. 67.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 67', '2026-05-13', 'static', 'statute_citation', 'Statewide executive officials', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('06efd9daa022b878', 'NH', '["state"]', 'candidate_eligibility', 'How is the New Hampshire State Treasurer selected?', '["Is there an election for State Treasurer in NH?","Who picks the NH State Treasurer?","Appointment vs election for NH Treasurer"]', 'Similar to the Secretary of State, the New Hampshire State Treasurer is elected by a joint ballot of the House of Representatives and the Senate under N.H. Const. Pt. 2, Art. 67, and does not appear on the popular ballot for voters.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 67', '2026-05-13', 'static', 'statute_citation', 'Statewide executive officials', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('918fdc7e922f5c5e', 'NH', '["state"]', 'redistricting', 'What is the size of the New Hampshire House of Representatives?', '["How many members are in the NH House?","Largest state legislative bodies","Composition of the NH General Court"]', 'The New Hampshire House of Representatives consists of 400 members, making it the third-largest legislative body in the English-speaking world. Under N.H. Const. Pt. 2, Art. 9, all 400 seats are up for election every two years.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 9', '2026-05-13', 'static', 'statute_citation', 'State House candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('9938ab398d34a8de', 'NH', '["state"]', 'redistricting', 'What is the size of the New Hampshire State Senate?', '["How many state senators does NH have?","NH Senate composition 2026","Size of the NH Senate"]', 'The New Hampshire State Senate consists of 24 members representing 24 districts. Under N.H. Const. Pt. 2, Art. 25, senators are elected to two-year terms concurrently with the House.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 25', '2026-05-13', 'static', 'statute_citation', 'State Senate candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('430ab0dc558ff6e0', 'NH', '["state"]', 'candidate_eligibility', 'What are the term lengths for New Hampshire state legislators?', '["How long is a NH House term?","NH State Senate term length","Legislative election cycle New Hampshire"]', 'Both New Hampshire State Representatives and State Senators serve two-year terms. Every seat in both the 400-member House and the 24-member Senate is up for election in every even-numbered year.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 9 and Art. 25', '2026-05-13', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('98598e1f3627f2c7', 'NH', '["state"]', 'candidate_eligibility', 'What is the annual salary for New Hampshire state legislators?', '["How much are NH House members paid?","Legislative salary New Hampshire","Is the NH legislature a part-time job?"]', 'New Hampshire legislators are the lowest-paid in the U.S. Under N.H. Const. Pt. 2, Art. 15, members receive $200 per biennial term ($100/year). Presiding officers receive $250. Mileage is limited to 45 legislative days; special sessions add $3/day for up to 15 days.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 15', '2026-05-13', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('579cf47024738b83', 'NH', '["federal","state","county"]', 'election_dates', 'When is the 2026 New Hampshire State Primary Election?', '["What date is the NH primary in 2026?","New Hampshire September primary date","Late primary elections NH"]', 'The 2026 New Hampshire State Primary Election is scheduled for Tuesday, September 8, 2026. This partisan primary is distinct from the earlier presidential primary and is held on the second Tuesday of September per RSA 653:7.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/653/653-7.htm', 'RSA 653:7', '2026-05-13', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('b8f9cc61842aa1e4', 'NH', '["federal"]', 'election_dates', 'What is the ''First-in-the-Nation'' primary mandate in New Hampshire?', '["NH presidential primary date mandate","RSA 653:9 first in nation","How is the NH primary date determined?"]', 'Under RSA 653:9, New Hampshire''s presidential primary must be held at least seven days before any ''similar election'' in any other state. This statutory mandate requires the Secretary of State to set a date that ensures New Hampshire remains the first primary in the nation.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/653/653-9.htm', 'RSA 653:9', '2026-05-13', 'static', 'statute_citation', 'Federal candidates and voters', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('92a8f293b84ba0d0', 'NH', '["state"]', 'election_dates', 'Who has the authority to set the date for the New Hampshire primary?', '["Can the Secretary of State move the NH primary date?","Who controls the NH election calendar?","RSA 653:9 primary scheduling"]', 'The New Hampshire Secretary of State has the sole authority to set the date of the presidential primary to comply with the first-in-the-nation mandate. For the state primary in September, the date is fixed by statute (RSA 653:7) unless a conflict arises with specific holidays.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/653/653-9.htm', 'RSA 653:9 and RSA 653:7', '2026-05-13', 'static', 'statute_citation', 'Election administration and candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('0e35979401695271', 'NH', '["state"]', 'finance_ethics', 'What are the individual and corporate contribution limits for state candidates in New Hampshire?', '["Max donation for NH Governor 2026","How much can an individual give to a candidate in NH?","RSA 664:4 contribution limits"]', 'Under RSA 664:4, individuals and corporations may contribute up to $15,000 per candidate per election cycle. This limit was increased by 2023 legislative reforms (SB 140) and applies uniformly to persons and entities.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-4.htm', 'RSA 664:4, I', '2026-05-13', 'per_cycle', 'statute_citation', 'State candidates and donors', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('0368e5aee1269bf2', 'NH', '["state"]', 'finance_ethics', 'What are the contribution limits for political committees and parties in New Hampshire?', '["PAC donation limits NH","How much can I give to a political party in New Hampshire?","NH campaign finance caps 2026"]', 'Individuals and businesses may contribute up to $30,000 per election cycle to a political committee or a political party. These caps are governed by RSA 664:4, V, and are distinct from limits on direct contributions to candidates.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-4.htm', 'RSA 664:4, V', '2026-05-13', 'per_cycle', 'statute_citation', 'Political Committees and Party units', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('ff29f624f4fdb713', 'NH', '["state"]', 'finance_ethics', 'What is a Political Advocacy Organization (PAO) and what are its contribution limits?', '["NH unlimited campaign contributions loophole","PAO status campaign finance","Can PAOs give unlimited money to candidates?"]', 'A Political Advocacy Organization (PAO) is a registered entity that can accept unlimited contributions from donors. Under RSA 664:4, V, a PAO may also make unlimited direct contributions to other committees, including candidate committees, effectively allowing for unlimited pass-through fundraising.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-4.htm', 'RSA 664:2, XIV and RSA 664:4, V', '2026-05-13', 'static', 'statute_citation', 'Candidates and Super PACs', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('794b97baf84b99de', 'NH', '["state"]', 'finance_ethics', 'Are direct corporate contributions to candidates legal in New Hampshire?', '["Can a business use treasury funds to donate in NH?","NH corporate treasury donation rules","Kennedy v Gardner corporate contributions"]', 'Yes. While specific older statutes still contain restrictive language, direct corporate treasury contributions are permitted in New Hampshire up to the individual limit of $15,000 per cycle. This follows federal court rulings and the 2023 consolidation of limits under RSA 664:4.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-4.htm', 'RSA 664:4', '2026-05-13', 'static', 'statute_citation', 'Corporations and Campaign Treasurers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('627cb4214d31f460', 'NH', '["state","county"]', 'finance_ethics', 'Is the Online Campaign Finance System (OCFS) mandatory for candidates in New Hampshire?', '["Do I have to file my NH campaign reports online?","RSA 664:9-a online filing","Electronic filing requirements for NH State House"]', 'Online filing is mandatory for Governor, Executive Council, and State Senate candidates under RSA 664:9-a. It will become mandatory for State House and all other elective offices, including county positions, as of November 25, 2026.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-9-a.htm', 'RSA 664:9-a', '2026-05-13', 'per_cycle', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('47f137d22741dcac', 'NH', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in New Hampshire?', '["New Hampshire voter ID laws","Poll ID requirements NH","Can I vote in NH without a driver''s license?"]', 'Yes. Voters must present a valid photo ID to vote in person under RSA 659:13. Valid IDs include NH driver''s licenses, U.S. passports, military IDs, and student IDs from NH schools that meet specific criteria.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/659/659-13.htm', 'RSA 659:13', '2026-05-13', 'static', 'statute_citation', 'All voters', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('8d82a63012efc055', 'NH', '["federal","state","county","municipal"]', 'voter_interaction', 'Does New Hampshire allow same-day voter registration?', '["Can I register to vote at the polls in NH?","Election day registration New Hampshire","How late can I register to vote in NH?"]', 'Yes. New Hampshire allows eligible citizens to register and vote on the same day at their polling place. Voters must provide proof of identity, citizenship, age, and domicile at the time of registration per RSA 654:7-a.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/654/654-7-a.htm', 'RSA 654:7-a', '2026-05-13', 'static', 'statute_citation', 'Unregistered voters', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('0a8575ef3efec2a3', 'NH', '["federal","state","county","municipal"]', 'voter_interaction', 'Does New Hampshire have no-excuse early voting?', '["When can I vote early in NH?","Does NH have a general early voting period?","Absentee vs early voting in New Hampshire"]', 'No. New Hampshire does not offer no-excuse early voting. Voters must cast their ballot in person on Election Day, unless they meet the statutory requirements to request an absentee ballot.', 'https://www.sos.nh.gov/elections/voters/absentee-ballots', 'New Hampshire Secretary of State – Absentee Voting', '2026-05-13', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('25f26105fe59aa23', 'NH', '["judicial"]', 'candidate_eligibility', 'How are judges selected in New Hampshire, and are there retirement rules?', '["NH judicial selection process","Who appoints Supreme Court justices in NH?","NH judicial age limit"]', 'NH judges are appointed by the Governor and confirmed by a majority vote of the Executive Council under N.H. Const. Pt. 2, Art. 46. The system includes the 5-justice Supreme Court and Superior/District courts. All judges face mandatory retirement at age 70 per N.H. Const. Pt. 2, Art. 78.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 46 and Art. 78', '2026-05-13', 'static', 'statute_citation', 'Judicial candidates and nominees', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('28d64575761b99f8', 'NH', '["state","judicial"]', 'recall_rules', 'Can voters recall state officials or judges in New Hampshire?', '["Recall mechanism NH","How to remove a NH state legislator","Does New Hampshire have a recall by petition?"]', 'No. New Hampshire does not have a constitutional or statutory mechanism for the recall of statewide officials, legislators, or judges by voter petition. Removal is only possible via the legislative impeachment process or specific disciplinary actions.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'New Hampshire Constitution', '2026-05-13', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('229173c318b81d5e', 'NH', '["federal"]', 'candidate_eligibility', 'What are the residency and age requirements for New Hampshire U.S. Senate candidates?', '["Senate age requirement NH","How long to live in NH for Senate?","US Senate inhabitant rule"]', 'Under the U.S. Constitution Article I § 3, a candidate must be at least 30 years old, a U.S. citizen for nine years, and an inhabitant of New Hampshire at the time of the election.', 'https://www.sos.nh.gov/elections/candidates/running-office', 'New Hampshire Secretary of State – Running for Office', '2026-05-13', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('dc96c5219a668edb', 'NH', '["federal"]', 'candidate_eligibility', 'What are the residency and age requirements for New Hampshire U.S. House candidates?', '["House age requirement NH","How long to live in NH for US House?","District inhabitant rule NH"]', 'Per the U.S. Constitution Article I § 2, a candidate must be at least 25 years old, a U.S. citizen for seven years, and an inhabitant of New Hampshire when elected. Residency within the specific congressional district is not a constitutional requirement.', 'https://www.sos.nh.gov/elections/candidates/running-office', 'New Hampshire Secretary of State – Running for Office', '2026-05-13', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('c0543525f3e0e394', 'NH', '["state"]', 'candidate_eligibility', 'What are the inhabitant and age requirements for the New Hampshire State Senate?', '["NH State Senate eligibility","Senate age threshold NH","7-year inhabitant rule NH"]', 'Under N.H. Const. Pt. 2, Art. 29, State Senate candidates must be at least 30 years old and have been an inhabitant of New Hampshire for seven years immediately preceding the election. They must also be an inhabitant of the district they represent when elected.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 29', '2026-05-13', 'static', 'statute_citation', 'State Senate candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('233668f6350c462f', 'NH', '["state"]', 'candidate_eligibility', 'What are the inhabitant and age requirements for the New Hampshire State House of Representatives?', '["NH State House eligibility","House age threshold NH","2-year inhabitant rule NH"]', 'Under N.H. Const. Pt. 2, Art. 14, State House candidates must be at least 18 years old and have been an inhabitant of New Hampshire for two years. They must also be an inhabitant of the town, ward, or district they represent when elected.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 14', '2026-05-13', 'static', 'statute_citation', 'State House candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('d8d8e298562aafa0', 'NH', '["state"]', 'candidate_eligibility', 'What are the residency and age requirements for the New Hampshire Executive Council?', '["Executive Council eligibility NH","Council age threshold NH","7-year inhabitant rule Council"]', 'Executive Council candidates must be at least 30 years old, a registered voter, and an inhabitant of New Hampshire for at least seven years preceding the election. They must also be a resident of the district they seek to represent.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 61', '2026-05-13', 'static', 'statute_citation', 'Executive Council candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('62c2f2e45b516bd9', 'NH', '["state"]', 'candidate_eligibility', 'Is Senator Maggie Hassan''s seat up for election in 2026?', '["When is Maggie Hassan up for re-election?","NH Senate seats on the 2026 ballot","Is both NH Senate seats open in 2026?"]', 'No. Senator Maggie Hassan (D) was re-elected in 2022 to a six-year term. Her seat is not on the ballot for the 2026 cycle; she is next up for re-election in 2028.', 'https://www.sos.nh.gov/elections/upcoming-elections', 'New Hampshire Secretary of State – Upcoming Elections', '2026-05-13', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('fbba455c828c4b9f', 'NH', '["state"]', 'election_dates', 'What is the order of succession if the Governor of New Hampshire is unable to serve?', '["NH Governor succession rules","Who takes over if the Governor resigns NH?","No Lt Gov succession plan"]', 'Under N.H. Const. Pt. 2, Art. 49, if the Governor''s office becomes vacant, the President of the Senate assumes the duties. If the Senate President is also unable to serve, the Speaker of the House is next in the line of succession.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 49', '2026-05-13', 'static', 'statute_citation', 'Statewide officials', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('194a18de8836f879', 'NH', '["state","county"]', 'election_dates', 'What are the filing deadlines for the 2026 partisan primary in New Hampshire?', '["Filing window NH primary 2026","When to file for NH office?","RSA 655 filing dates"]', 'The candidate filing window for the September 8, 2026 partisan primary typically opens on the first Wednesday in June and closes on the second Friday. For the 2026 cycle, this period is approximately June 3 to June 12, 2026, per RSA 655:14.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/655/655-14.htm', 'RSA 655:14', '2026-05-13', 'per_cycle', 'statute_citation', 'All partisan candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('f22685a50ac116f7', 'NH', '["federal","state","county"]', 'election_dates', 'What is the filing deadline for independent candidates in the 2026 New Hampshire general election?', '["NH independent candidate deadline 2026","When to file nomination papers NH?","Nomination by petition deadline NH"]', 'Independent or non-party candidates must file their nomination papers and declarations of candidacy no later than 5:00 p.m. on the Wednesday one week before the state primary. For the 2026 cycle, the deadline is September 2, 2026, per RSA 655:43.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/655/655-43.htm', 'RSA 655:43', '2026-05-13', 'per_cycle', 'statute_citation', 'Independent candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('150a6261a6fe0ea9', 'NH', '["federal","state","county","municipal"]', 'voter_interaction', 'What is a ''challenged ballot'' in New Hampshire election law?', '["NH provisional ballot equivalent","Voting if your identity is challenged NH","RSA 659:12 procedures"]', 'New Hampshire uses a ''challenged ballot'' mechanism under RSA 659:12. If a voter''s eligibility is questioned, they may still vote after signing a challenged voter affidavit. Their ballot is marked and segregated for potential review if the election result is contested.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/659/659-12.htm', 'RSA 659:12', '2026-05-13', 'static', 'statute_citation', 'Voters and poll watchers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('de8bf5f03be3ddb9', 'NH', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voter registration lists maintained in New Hampshire?', '["NH voter roll purges","HAVA list maintenance NH","Periodic voter list cleaning"]', 'Voter lists are maintained by municipal supervisors of the checklist. Under HAVA and state law, lists are updated following each election. Every ten years, supervisors must conduct a mandatory review and verification of the entire checklist to remove ineligible entries.', 'https://www.sos.nh.gov/elections/voters/voter-registration-information', 'New Hampshire Secretary of State – Voter Registration', '2026-05-13', 'static', 'official_source_direct', 'Election officials and campaigns', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('757b073976fe4241', 'NH', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the rules for college student voting domicile in New Hampshire?', '["Can out-of-state students vote in NH?","HB 1264 student voting effect","College student residency requirements NH"]', 'Following the enactment of HB 1264, any person who votes in New Hampshire establishes ''domicile.'' For students, this means that while they may vote, they become subject to New Hampshire laws regarding motor vehicle registration and driver''s licensing.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/654/654-1.htm', 'RSA 654:1', '2026-05-13', 'static', 'statute_citation', 'Student voters', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('9c8df6df1e626ea5', 'NH', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a witness signature required on New Hampshire absentee ballots?', '["NH absentee witness requirement","Does someone have to sign my mail ballot envelope?","Absentee ballot verification NH"]', 'No. New Hampshire does not require a witness signature or a notary for an absentee ballot to be counted. The voter''s identity is verified by comparing the signature on the affidavit envelope with the signature on the absentee ballot application.', 'https://www.sos.nh.gov/elections/voters/absentee-ballots', 'New Hampshire Secretary of State – Absentee Voting', '2026-05-13', 'static', 'official_source_direct', 'Absentee voters', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('dd18a92bd5407907', 'NH', '["state","county","municipal"]', 'finance_ethics', 'What is the donor itemization threshold for occupation and employer reporting in New Hampshire?', '["NH donor occupation disclosure limit","When to list employer for campaign gifts NH","HB 1380 disclosure changes"]', 'Under the 2024 legislative reform (HB 1380), the threshold for disclosing a contributor''s occupation and employer was increased. Campaigns must now itemize this information for any individual who contributes more than $1,000 in aggregate during an election cycle.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-6.htm', 'RSA 664:6, I', '2026-05-13', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('23b6fd308f269a03', 'NH', '["state","county","municipal"]', 'finance_ethics', 'What is the threshold for public disclosure of contributor identifying information in New Hampshire?', '["NH public donor disclosure limit","Right-to-Know donor information NH","RSA 664:6 transparency rules"]', 'Under 2024 reforms and the Right-to-Know exemption (RSA 91-A), the name and address of an individual contributor are subject to public disclosure only if their aggregate contributions exceed $200 during the election cycle.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-6.htm', 'RSA 664:6, I-a', '2026-05-13', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('efa7b04dc3724d33', 'NH', '["state","county","municipal"]', 'finance_ethics', 'What is the threshold for reporting an independent expenditure in New Hampshire?', '["NH independent expenditure threshold","When to file an IE report NH","RSA 664:13 reporting"]', 'Any person or political committee that spends more than $1,000 in aggregate on an independent expenditure must file a disclosure report with the Secretary of State under RSA 664:13. If the expenditure exceeds $5,000 within 24 hours, a report must be filed within 24 hours.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-13.htm', 'RSA 664:13 and 664:13-a', '2026-05-13', 'static', 'statute_citation', 'PACs and Super PACs', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('f827b1d7f67f4c7c', 'NH', '["state","county","municipal"]', 'finance_ethics', 'What is the ''Paid for by'' attribution requirement for political advertising in New Hampshire?', '["NH political ad disclaimer rules","Who paid for this ad disclaimer NH","RSA 664:14 requirements"]', 'Under RSA 664:14, almost all political advertisements—including print, broadcast, and electronic messages—must clearly and conspicuously state the name and address of the person or committee who paid for and authorized the communication.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-14.htm', 'RSA 664:14', '2026-05-13', 'static', 'statute_citation', 'All Campaigns and Printers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('a92b9304e08f7a10', 'NH', '["state"]', 'finance_ethics', 'How do voluntary spending limits work in New Hampshire state elections?', '["NH voluntary spending cap","RSA 664:5-a spend limit","Waiving filing fees NH"]', 'Under RSA 664:5-a, candidates for Governor, Executive Council, or State Senate who voluntarily agree to a specific campaign spending cap are exempt from both the filing fee and the signature petition requirements for ballot access.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-5-a.htm', 'RSA 664:5-a', '2026-05-13', 'static', 'statute_citation', 'Statewide and State Senate candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('57e759cd48394789', 'NH', '["state","county","municipal"]', 'finance_ethics', 'What is the anonymous campaign contribution cap in New Hampshire?', '["Can I donate cash anonymously in NH?","NH anonymous contribution limit","RSA 664:4-b thresholds"]', 'Under RSA 664:4-b, anonymous campaign contributions are strictly prohibited. Any anonymous contribution received must be delivered within 48 hours to the State Treasurer for deposit into the general fund.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-4-b.htm', 'RSA 664:4-b', '2026-05-13', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('62fcbf06c979a811', 'NH', '["state"]', 'redistricting', 'What are ''floterial districts'' in the New Hampshire House of Representatives?', '["NH House floterial districts","Multi-town legislative seats NH","How are NH House seats allocated?"]', 'Floterial districts are a unique New Hampshire redistricting feature where a single legislative seat ''floats'' over multiple towns or wards to satisfy population equality. This allows for proportional representation in areas where town populations do not neatly align with a single-seat quota.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 11-a', '2026-05-13', 'static', 'statute_citation', 'State House candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('11b0aa0a59c222ab', 'NH', '["state","county","municipal"]', 'ballot_access', 'Does New Hampshire have a single-subject rule for state legislation?', '["Omnibus bill rules NH","NH legislature multi-topic bills","Constitutional single subject rule NH"]', 'No. New Hampshire is one of the few states that does not have a constitutional or statutory single-subject rule for legislation. This permits the passage of omnibus bills that contain multiple, unrelated topics in a single legislative act.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'New Hampshire Constitution', '2026-05-13', 'static', 'statute_citation', 'State Legislators and Lobbyists', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('3b6edf011a0d07cc', 'NH', '["state"]', 'ballot_access', 'How are constitutional amendments referred to the voters in New Hampshire?', '["NH constitutional amendment process","2/3 voter ratification threshold","N.H. Const. Art. 100 requirements"]', 'New Hampshire has the highest ratification threshold in the nation. Under N.H. Const. Pt. 2, Art. 100, an amendment must be passed by a 3/5 majority in both the House and Senate, then ratified by at least 2/3 of the voters in a general election.', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 100', '2026-05-13', 'static', 'statute_citation', 'State Legislators and Campaigns', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('51ae5d9b11c25cd3', 'NH', '["municipal"]', 'election_dates', 'What is the traditional ''Town Meeting Day'' in New Hampshire?', '["When is NH Town Meeting?","NH local election day","March town meeting dates"]', 'Annual Town Meeting is traditionally held on the second Tuesday of March for the vast majority of New Hampshire towns. This day is used for direct democracy, where voters approve budgets, tax rates, and elect town officials.', 'https://www.gencourt.state.nh.us/rsa/html/III/39/39-1.htm', 'RSA 39:1', '2026-05-13', 'static', 'statute_citation', 'Municipal candidates and voters', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('cb69c27b1227f1bb', 'NH', '["state"]', 'election_dates', 'How often is the question of a constitutional convention put to New Hampshire voters?', '["NH decennial convention vote","When is the next NH convention question?","Art. 100 convention rule"]', 'Under N.H. Const. Pt. 2, Art. 100, a question asking voters whether a convention should be called to revise or amend the state constitution must appear on the general election ballot every 10 years (e.g., 2022, 2032).', 'https://www.gencourt.state.nh.us/constitution/constitution.htm', 'N.H. Const. Pt. 2, Art. 100', '2026-05-13', 'static', 'statute_citation', 'Voters and Strategists', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('68690a1de4503825', 'NH', '["state","county"]', 'finance_ethics', 'When are the pre-election campaign finance reports due in New Hampshire?', '["NH campaign reporting schedule","20-day pre-election report deadline","NH periodic filing dates"]', 'Candidates must file primary and general election disclosure reports with the Secretary of State on the 20th day before the election and the 8th day before the election, as well as a post-election report on the 10th day after the election.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-6.htm', 'RSA 664:6', '2026-05-13', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('14cc8cc84c2929b9', 'NH', '["state"]', 'finance_ethics', 'Does New Hampshire have rules regarding the personal use of campaign funds?', '["Can I use campaign money for my mortgage NH?","Personal use prohibition NH campaign finance","RSA 664:4-c restrictions"]', 'Yes. Under RSA 664:4-c, campaign contributions must be used for expenses directly related to the election. Personal use, such as paying for a candidate''s personal mortgage, rent, or luxury items, is strictly prohibited.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-4-c.htm', 'RSA 664:4-c', '2026-05-13', 'static', 'statute_citation', 'Candidates and Treasurers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('54bfd5b7e9f61f60', 'NH', '["state"]', 'ballot_access', 'How many signatures are required for independent candidates for Governor or U.S. Senator in New Hampshire?', '["NH independent signature requirement","Nomination paper signatures for statewide office NH","3,000 signature rule NH"]', 'Under RSA 655:42, an independent (non-party) candidate for Governor or U.S. Senator must collect at least 3,000 valid signatures on nomination papers from registered voters to qualify for the general election ballot.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/655/655-42.htm', 'RSA 655:42', '2026-05-13', 'static', 'statute_citation', 'Independent candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('a4f0eab3f2c631d4', 'NH', '["state"]', 'ballot_access', 'What is the role of the New Hampshire Ballot Law Commission?', '["NH Ballot Law Commission power","Who decides ballot access disputes in NH?","RSA 665 review process"]', 'The Ballot Law Commission is a bipartisan body under RSA 665 that hears and decides all disputes regarding candidate qualifications, nomination petitions, and the wording of ballot questions.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/665/665-1.htm', 'RSA 665:1', '2026-05-13', 'static', 'statute_citation', 'Candidates and Legal Counsel', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('b1d6a5acf6b35ffc', 'NH', '["state"]', 'finance_ethics', 'Does New Hampshire require inaugural committees to file financial reports?', '["NH Governor inaugural committee rules","Reporting for Governor party funds","SoS inaugural committee filing"]', 'Yes. While not candidate committees, gubernatorial inaugural committees must register with the Secretary of State and file a financial disclosure report within 90 days after the inaugural activities are completed.', 'https://www.sos.nh.gov/elections/campaign-finance', 'New Hampshire Secretary of State – Campaign Finance', '2026-05-13', 'per_cycle', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('6b7072914f2ed547', 'NH', '["state","county"]', 'finance_ethics', 'Are candidates required to appoint a campaign treasurer in New Hampshire?', '["NH treasurer registration requirement","Who can be a campaign treasurer in NH?","RSA 664:6 treasurer rules"]', 'Yes. Under RSA 664:6, every candidate for state or county office who receives or spends funds must appoint a campaign treasurer. The name and address of the treasurer must be filed with the Secretary of State before any financial activity occurs.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-6.htm', 'RSA 664:6', '2026-05-13', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('49ab09ce9073cd09', 'NH', '["state"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late in New Hampshire?', '["NH late filing fines","Campaign finance penalty schedule NH","RSA 664:20 penalties"]', 'Under RSA 664:20, the Secretary of State can assess a fine of $10 per day for each day a campaign report remains delinquent. Repeated or willful failures to file can result in criminal prosecution.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-20.htm', 'RSA 664:20', '2026-05-13', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('aa694331c2cdf9a7', 'NH', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the rules regarding voter registration deadlines in New Hampshire?', '["Last day to register by mail in NH","NH voter registration cutoff","RSA 654:12 deadlines"]', 'Voters can register in person at their town or city clerk''s office up to approximately 6 to 13 days before an election (varies by municipality). Additionally, New Hampshire offers Election Day Registration at all polling places.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/654/654-12.htm', 'RSA 654:12', '2026-05-13', 'static', 'statute_citation', 'All voters', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('d7b8159390c2ae44', 'NH', '["federal","state","county","municipal"]', 'voter_interaction', 'Does New Hampshire law allow time off for employees to vote?', '["NH voting leave law","Do I get paid to vote in New Hampshire?","Employer requirements for Election Day"]', 'No. New Hampshire is one of the few states that does not have a statute requiring employers to grant time off (paid or unpaid) for employees to vote. Employees must generally coordinate with their employers or utilize absentee voting if eligible.', 'https://www.sos.nh.gov/elections/voters/voting-new-hampshire', 'New Hampshire Secretary of State', '2026-05-13', 'static', 'official_source_direct', 'Voters and Employers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('db0a153762d4aa74', 'NH', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the criminal penalties for voter intimidation in New Hampshire?', '["Is voter intimidation illegal in NH?","NH RSA 659:40 penalties","Coercing voters in New Hampshire"]', 'Under RSA 659:40, using force, threats, or intimidation to influence a person to vote or refrain from voting, or to interfere with the free exercise of the franchise, is a misdemeanor. If the act involves a public official, it may be elevated.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/659/659-40.htm', 'RSA 659:40', '2026-05-13', 'static', 'statute_citation', 'All voters and Campaigns', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('735ac02d46020f97', 'NH', '["state","county"]', 'election_dates', 'How are vacancies in the New Hampshire General Court filled?', '["NH state senate special elections","Filling legislative seats in NH","RSA 661 vacancy procedures"]', 'Vacancies in the House of Representatives or State Senate are filled by special election. The Governor and Executive Council must issue a precept for a special election within a specific timeframe after the vacancy occurs under RSA 661:8.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/661/661-8.htm', 'RSA 661:8', '2026-05-13', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('1fdf6a32aaad53e1', 'NH', '["state"]', 'election_dates', 'How are vacancies in the New Hampshire Executive Council filled?', '["Executive Council special elections","Filling a Council seat NH","RSA 661:5 rules"]', 'If an Executive Council seat becomes vacant, a special election must be held. The Governor and the remaining members of the Council issue a precept setting the date for the election to fill the unexpired term per RSA 661:5.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/661/661-5.htm', 'RSA 661:5', '2026-05-13', 'static', 'statute_citation', 'Executive Council candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('6251fa2c3d1c479c', 'NH', '["county"]', 'election_dates', 'How are vacancies in New Hampshire county offices filled?', '["NH county sheriff vacancy fill","Who appoints county officials NH?","County officer succession"]', 'Vacancies in elected county offices (Sheriff, Attorney, Treasurer, etc.) are filled by an appointment from the Superior Court judges for that county. The appointee serves until the next general election.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/661/661-9.htm', 'RSA 661:9', '2026-05-13', 'static', 'statute_citation', 'County-level candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('b0841ab212d49b15', 'NH', '["municipal"]', 'election_dates', 'What is an ''SB 2'' town in New Hampshire?', '["RSA 40:13 ballot voting","Deliberative session vs Town Meeting","Official ballot voting towns"]', 'An ''SB 2'' town (named after Senate Bill 2) uses the official ballot voting system under RSA 40:13. These towns have a deliberative session to discuss warrant articles, followed by a subsequent day of traditional booth voting on the articles, instead of the traditional open Town Meeting.', 'https://www.gencourt.state.nh.us/rsa/html/III/40/40-13.htm', 'RSA 40:13', '2026-05-13', 'static', 'statute_citation', 'Municipal candidates and voters', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('c815bb901136d785', 'NH', '["county"]', 'election_dates', 'What is the term length for elected county officials in New Hampshire?', '["How long is a NH Sheriff''s term?","County Attorney term duration NH","NH County Commissioner elections"]', 'All elected county officers in New Hampshire—including Sheriff, County Attorney, Treasurer, Register of Deeds, Register of Probate, and County Commissioners—serve two-year terms and are elected in partisan contests in even-numbered years.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/653/653-1.htm', 'RSA 653:1', '2026-05-13', 'static', 'statute_citation', 'County-level candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('b0577c606448fc8a', 'NH', '["federal","state","county"]', 'ballot_access', 'What is an ''Assent to Candidacy'' in New Hampshire ballot access?', '["NH primary petition assent","Candidate consent form NH","RSA 655:25 requirements"]', 'When candidates utilize the primary petition signature alternative for ballot access, they must also file an official ''Assent to Candidacy'' under RSA 655:25, formally declaring they are qualified for the office and will accept the nomination.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/655/655-25.htm', 'RSA 655:25', '2026-05-13', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('f1b3154137a892df', 'NH', '["state","county","municipal"]', 'ballot_access', 'What is the ''last day'' in-person filing requirement in New Hampshire?', '["Filing on the deadline NH","RSA 655:43 in person rule","Can I mail my NH candidate filing on the last day?"]', 'Under RSA 655:43, any candidate or person submitting nomination papers or declarations on the final day of the filing period must deliver them in person to the filing officer by 5:00 p.m. Filings mailed and arriving on the last day may be rejected if not received by the deadline.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/655/655-43.htm', 'RSA 655:43', '2026-05-13', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('3db6014e593969a4', 'NH', '["state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance at New Hampshire polling places?', '["NH 10-foot buffer zone rule","Where to stand at the polls NH","Campaigning near poll entrances"]', 'New Hampshire enforces a 10-foot electioneering buffer zone measured from the entrance to the building containing the polling place. Under RSA 659:43, no person may electioneer or distribute campaign materials within this specific corridor.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/659/659-43.htm', 'RSA 659:43', '2026-05-13', 'static', 'statute_citation', 'Campaigns and Poll Workers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('15cba03912d7c73d', 'NH', '["state"]', 'finance_ethics', 'What are the rules regarding candidate loans to their own campaigns in New Hampshire?', '["NH candidate loan limits","Can I lend my campaign money NH?","Repayment rules for candidate loans"]', 'Candidates may make unlimited personal loans to their own campaigns in New Hampshire. However, these loans must be formally documented as debt in campaign finance reports and must be repaid using legal campaign contributions.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-6.htm', 'RSA 664:6', '2026-05-13', 'static', 'statute_citation', 'Candidates and Treasurers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1'),
  ('c4b3afb62f08d914', 'NH', '["state"]', 'finance_ethics', 'Is out-of-state PAC registration required in New Hampshire?', '["NH out of state committee rules","Reporting for national PACs in NH","RSA 664 registration for foreign committees"]', 'Yes. Any out-of-state or national political committee that intends to spend more than $1,000 in a New Hampshire election must formally register as a political committee with the Secretary of State and adhere to NH''s contribution and reporting rules.', 'https://www.gencourt.state.nh.us/rsa/html/LXIII/664/664-6.htm', 'RSA 664:6', '2026-05-13', 'static', 'statute_citation', 'Out-of-state PACs and Treasurers', 'batch_2026-05-13T16-36-28_new_hampshire_full_v1')
